class Solution {
    public String reverseWords(String s) {
        // Step 1: Reverse the entire string
        char[] charArray = s.toCharArray();
        reverse(charArray, 0, charArray.length - 1);

        // Step 2: Reverse each word in the reversed string
        int start = 0;
        for (int end = 0; end < charArray.length; end++) {
            if (charArray[end] == ' ') {
                reverse(charArray, start, end - 1);
                start = end + 1;
            }
        }
        reverse(charArray, start, charArray.length - 1);

        // Step 3: Trim leading and trailing spaces and ensure single spaces between words
        String result = new String(charArray);
        return result.trim().replaceAll("\\s+", " ");
    }

    private void reverse(char[] arr, int left, int right) {
        while (left < right) {
            char temp = arr[left];
            arr[left] = arr[right];
            arr[right] = temp;
            left++;
            right--;
        }
    }
}

