func reverseWords(s string) string {
    // Convert string to rune slice to handle Unicode characters
    runes := []rune(s)

    // Step 1: Reverse the entire string
    reverse(runes, 0, len(runes)-1)

    // Step 2: Reverse each word in the reversed string
    start := 0
    for i := 0; i <= len(runes); i++ {
        if i == len(runes) || runes[i] == ' ' {
            reverse(runes, start, i-1)
            start = i + 1
        }
    }

    // Step 3: Trim leading and trailing spaces and ensure single spaces between words
    result := make([]rune, 0, len(runes))
    for _, r := range runes {
        if len(result) == 0 && r == ' ' {
            continue
        }
        if len(result) > 0 && r == ' ' && result[len(result)-1] == ' ' {
            continue
        }
        result = append(result, r)
    }

    return string(result)
}

func reverse(runes []rune, start int, end int) {
    for start < end {
        runes[start], runes[end] = runes[end], runes[start]
        start++
        end--
    }
}

